// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Get all available property IDs
var props = StelPropertyMgr.getPropertyList();
core.debug("Total registered properties: " + props.length);

// Print the first 20 properties
for(var i = 0; i < Math.min(20, props.length); i++) {
    core.debug(props[i]);
}

// Find all properties related to stars
var starProps = [];
for(var i = 0; i < props.length; i++) {
    if(props[i].indexOf("Star") >= 0 || props[i].indexOf("star") >= 0) {
        starProps.push(props[i]);
    }
}
core.debug("Star-related properties: " + starProps.length);

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Enumerate all properties with their values and types
var allProps = StelPropertyMgr.getAllProperties();
core.debug("All properties count: " + allProps.length);

// Analyze each property
for(var i = 0; i < Math.min(10, allProps.length); i++) {
    var prop = allProps[i];
    core.debug("Property: " + prop.getId() + ", Value: " + prop.getValue() + ", ReadOnly: " + prop.isReadOnly());
}

// Find all writable properties
var writableProps = [];
for(var i = 0; i < allProps.length; i++) {
    if(!allProps[i].isReadOnly()) {
        writableProps.push(allProps[i].getId());
    }
}
core.debug("Writable properties: " + writableProps.length);

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Get a specific property and examine it
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    core.debug("MilkyWay.intensity found");
    core.debug("Current value: " + prop.getValue());
    core.debug("Is read-only: " + prop.isReadOnly());
    core.debug("Can notify changes: " + prop.canNotify());
} else {
    core.debug("Property not found");
}

// Suppress warnings for optional plugin properties
var pluginProp = StelPropertyMgr.getProperty("Oculars.enabled", true);
if(pluginProp) {
    core.debug("Oculars plugin property is available");
}

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Read various property values
var starScale = StelPropertyMgr.getStelPropertyValue("StelSkyDrawer.absoluteStarScale");
core.debug("Absolute star scale: " + starScale);

var milkyWayIntensity = StelPropertyMgr.getStelPropertyValue("MilkyWay.intensity");
core.debug("Milky Way intensity: " + milkyWayIntensity);

var flagLines = StelPropertyMgr.getStelPropertyValue("ConstellationMgr.flagLines");
core.debug("Constellation lines visible: " + flagLines);

// Use noWarning for potentially missing properties
var ocularsEnabled = StelPropertyMgr.getStelPropertyValue("Oculars.enabled", true);
if(ocularsEnabled !== undefined) {
    core.debug("Oculars enabled: " + ocularsEnabled);
}

// Note: The C++ macro GETSTELPROPERTYVALUE is also available in C++ code:
// GETSTELPROPERTYVALUE("LandscapeMgr.atmosphereVisible")

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Enable constellation lines
var result = StelPropertyMgr.setStelPropertyValue("ConstellationMgr.flagLines", true);
core.debug("Constellation lines enabled: " + result);

// Set Milky Way intensity to 75%
StelPropertyMgr.setStelPropertyValue("MilkyWay.intensity", 0.75);

// Set absolute star scale
StelPropertyMgr.setStelPropertyValue("StelSkyDrawer.absoluteStarScale", 1.2);

// Enable star twinkling
StelPropertyMgr.setStelPropertyValue("StelSkyDrawer.flagTwinkle", true);

// Set landscape atmosphere visibility
StelPropertyMgr.setStelPropertyValue("LandscapeMgr.atmosphereVisible", false);

// Attempt to set a read-only property (will fail silently)
var setResult = StelPropertyMgr.setStelPropertyValue("StelApp.version", "test");
if(!setResult) {
    core.debug("Could not set property (may be read-only or not found)");
}

// Toggle a boolean property
var current = StelPropertyMgr.getStelPropertyValue("ConstellationMgr.flagBoundaries");
StelPropertyMgr.setStelPropertyValue("ConstellationMgr.flagBoundaries", !current);

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Get metadata for a property
var metaProp = StelPropertyMgr.getMetaProperty("MilkyWay.intensity");
if(metaProp.isValid()) {
    core.debug("Property name: " + metaProp.name());
    core.debug("Property type: " + metaProp.typeName());
    core.debug("Is writable: " + metaProp.isWritable());
    core.debug("Has notify signal: " + metaProp.hasNotifySignal());
    core.debug("Is stored: " + metaProp.isStored());
    core.debug("Is designable: " + metaProp.isDesignable());
}

// Note: In practice, StelModules auto-register all Q_PROPERTY definitions.
// Manual registration is for special cases, typically done in C++ code.
// This example demonstrates the concept only.

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

core.debug("Manual property registration is typically done in C++ code.");
core.debug("StelModules auto-register all their Q_PROPERTY definitions.");
core.debug("Use getPropertyList() to see all available properties.");

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Note: All StelModules are automatically registered by StelModuleMgr.
// This function is rarely needed in scripts.
// StelProperty IDs follow the format: <ModuleName>.<propertyName>

core.debug("StelModule properties are auto-registered on load.");
core.debug("Use getPropertyList() to see all available properties.");
core.debug("Example property IDs: MilkyWay.intensity, ConstellationMgr.flagLines");

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Get a property and examine its ID
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    core.debug("Property ID: " + prop.getId());
}

// Enumerate all properties and print their IDs
var allProps = StelPropertyMgr.getAllProperties();
for(var i = 0; i < Math.min(5, allProps.length); i++) {
    var propId = allProps[i].getId();
    core.debug("Property #" + i + ": " + propId);
}

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Get value via StelProperty object
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    var val = prop.getValue();
    core.debug("Milky Way intensity: " + val);
}

// Compare two properties
var prop1 = StelPropertyMgr.getProperty("LandscapeMgr.atmosphereVisible");
var prop2 = StelPropertyMgr.getProperty("LandscapeMgr.fogVisible");
if(prop1 && prop2) {
    core.debug("Atmosphere: " + prop1.getValue());
    core.debug("Fog: " + prop2.getValue());
}

// Note: getStelPropertyValue() is more convenient for simple reads:
// StelPropertyMgr.getStelPropertyValue("MilkyWay.intensity")

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Set value via StelProperty object
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop && !prop.isReadOnly()) {
    var result = prop.setValue(0.5);
    core.debug("Milky Way intensity set to 0.5, success: " + result);
}

// Check if write succeeded
var atmosphereProp = StelPropertyMgr.getProperty("LandscapeMgr.atmosphereVisible");
if(atmosphereProp) {
    var result = atmosphereProp.setValue(true);
    core.debug("Atmosphere visibility set result: " + result);
}

// Attempting to set a read-only property
var readOnlyProp = StelPropertyMgr.getProperty("StelApp.version");
if(readOnlyProp && readOnlyProp.isReadOnly()) {
    core.debug("This property is read-only, cannot modify");
}

// Note: setStelPropertyValue() is more convenient for simple writes:
// StelPropertyMgr.setStelPropertyValue("MilkyWay.intensity", 0.5)

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Check if properties are writable before attempting to modify
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    if(prop.isReadOnly()) {
        core.debug("Cannot modify - property is read-only");
    } else {
        prop.setValue(0.7);
        core.debug("Value modified successfully");
    }
}

// Filter for writable properties only
var allProps = StelPropertyMgr.getAllProperties();
var writableCount = 0;
var readOnlyCount = 0;
for(var i = 0; i < allProps.length; i++) {
    if(allProps[i].isReadOnly()) {
        readOnlyCount++;
    } else {
        writableCount++;
    }
}
core.debug("Writable: " + writableCount + ", Read-only: " + readOnlyCount + ", Total: " + allProps.length);

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Find synchronizable properties (useful for RemoteControl plugin)
var allProps = StelPropertyMgr.getAllProperties();
var syncCount = 0;
for(var i = 0; i < allProps.length; i++) {
    if(allProps[i].isSynchronizable()) {
        syncCount++;
    }
}
core.debug("Synchronizable properties: " + syncCount + " out of " + allProps.length);

// Check a specific property
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    core.debug("MilkyWay.intensity is synchronizable: " + prop.isSynchronizable());
}

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Check which properties support change notifications
var allProps = StelPropertyMgr.getAllProperties();
var notifyCount = 0;
var noNotifyCount = 0;
for(var i = 0; i < allProps.length; i++) {
    if(allProps[i].canNotify()) {
        notifyCount++;
    } else {
        noNotifyCount++;
    }
}
core.debug("With notification: " + notifyCount + ", Without: " + noNotifyCount);

// Examine a specific property
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    core.debug("MilkyWay.intensity can notify changes: " + prop.canNotify());
}

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Check the type of various properties
var prop1 = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop1) {
    var typeVal = prop1.getType();
    core.debug("MilkyWay.intensity type code: " + typeVal);
    // Common type codes:
    // QMetaType::Bool = 1
    // QMetaType::Int = 2  
    // QMetaType::Double = 6
    // QMetaType::Float = 38
    // QMetaType::QString = 10
}

var prop2 = StelPropertyMgr.getProperty("ConstellationMgr.flagLines");
if(prop2) {
    core.debug("ConstellationMgr.flagLines type code: " + prop2.getType());
}

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Get detailed metadata about a property
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    var metaProp = prop.getMetaProp();
    if(metaProp.isValid()) {
        core.debug("Property name: " + metaProp.name());
        core.debug("Property type: " + metaProp.typeName());
        core.debug("Is writable: " + metaProp.isWritable());
        core.debug("Has notify: " + metaProp.hasNotifySignal());
        core.debug("Is constant: " + metaProp.isConstant());
        core.debug("Is final: " + metaProp.isFinal());
    }
}

// Compare with getMetaProperty() on StelPropertyMgr:
var metaProp2 = StelPropertyMgr.getMetaProperty("MilkyWay.intensity");
// Both return the same QMetaProperty information

// Get reference to the Property Manager
var StelPropertyMgr = StelApp.getStelPropertyManager();

// Find which object owns a property
var prop = StelPropertyMgr.getProperty("MilkyWay.intensity");
if(prop) {
    var target = prop.getTarget();
    if(target) {
        core.debug("Property owner: " + target.objectName);
        // Output: Property owner: MilkyWay
    }
}

// Group properties by their target object
var allProps = StelPropertyMgr.getAllProperties();
var targets = {};
for(var i = 0; i < allProps.length; i++) {
    var t = allProps[i].getTarget();
    if(t) {
        var name = t.objectName;
        if(!targets[name]) targets[name] = [];
        targets[name].push(allProps[i].getId());
    }
}

// Print properties grouped by module
var moduleNames = Object.keys(targets);
core.debug("Modules with properties: " + moduleNames.length);
for(var j = 0; j < Math.min(5, moduleNames.length); j++) {
    var mod = moduleNames[j];
    core.debug(mod + ": " + targets[mod].length + " properties");
}
